from typing import Dict
from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    root = etree.fromstring(xml_data.encode() if isinstance(xml_data, str) else xml_data)

    # Use XPath variables to avoid injection
    query = "/students/student[username=$u and password=$p]"
    results = root.xpath(query, u=username, p=password)

    if not results:
        return None

    student = results[0]
    info: Dict[str, str] = {}
    for child in student:
        info[child.tag] = child.text if child.text is not None else ""

    return info

from urllib.parse import quote


def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not isinstance(api_url, str) or not isinstance(user_id, str):
        return None

    if not user_id:
        return None

    # Validate user_id: allow only alphanumeric characters, underscore, and hyphen
    if not all(c.isalnum() or c in ('_', '-') for c in user_id):
        return None

    # Ensure the user_id is safely encoded to prevent injection into the URL
    safe_user_id = quote(user_id, safe='')

    base = api_url.rstrip('/')
    return f"{base}/{safe_user_id}"

