def _import_fixed_module(version):
    '''
    Import a module using only fixed, hard-coded names selected by a
    validated key. No user-controlled data reaches import_module.
    '''
    if version == '':
        return importlib.import_module('urllib')
    elif version == '2':
        return importlib.import_module('urllib2')
    elif version == '3':
        return importlib.import_module('urllib3')
    return None


