import ast
import operator

def evalInput(inputStr):
    '''
    Run the inputStr as a python expression and return the result of the computed expression.
    '''
    # Supported operators
    bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.LShift: operator.lshift,
        ast.RShift: operator.rshift,
        ast.BitOr: operator.or_,
        ast.BitXor: operator.xor,
        ast.BitAnd: operator.and_,
    }
    unary_ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Invert: operator.invert,
        ast.Not: operator.not_,
    }
    cmp_ops = {
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.Constant):
            return node.value
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in bin_ops:
                raise ValueError("Unsupported operator")
            return bin_ops[op_type](_eval(node.left), _eval(node.right))
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in unary_ops:
                raise ValueError("Unsupported operator")
            return unary_ops[op_type](_eval(node.operand))
        elif isinstance(node, ast.BoolOp):
            if isinstance(node.op, ast.And):
                result = True
                for v in node.values:
                    result = _eval(v)
                    if not result:
                        return result
                return result
            elif isinstance(node.op, ast.Or):
                result = False
                for v in node.values:
                    result = _eval(v)
                    if result:
                        return result
                return result
            raise ValueError("Unsupported boolean operator")
        elif isinstance(node, ast.Compare):
            left = _eval(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                op_type = type(op)
                if op_type not in cmp_ops:
                    raise ValueError("Unsupported comparison")
                right = _eval(comparator)
                if not cmp_ops[op_type](left, right):
                    return False
                left = right
            return True
        elif isinstance(node, ast.Tuple):
            return tuple(_eval(e) for e in node.elts)
        elif isinstance(node, ast.List):
            return [_eval(e) for e in node.elts]
        elif isinstance(node, ast.Set):
            return {_eval(e) for e in node.elts}
        elif isinstance(node, ast.Dict):
            return {_eval(k): _eval(v) for k, v in zip(node.keys, node.values)}
        else:
            raise ValueError("Unsupported expression")

    tree = ast.parse(inputStr, mode='eval')
    return _eval(tree)

import hashlib
import hmac


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if isinstance(certificate, str):
        certificate = certificate.encode('utf-8')

    computed_hash = hashlib.sha256(certificate).hexdigest()

    if isinstance(known_hash, bytes):
        known_hash = known_hash.decode('utf-8')

    return hmac.compare_digest(computed_hash, known_hash)

